   134→@layer base {
   135→  * {
   136→    @apply border-border outline-ring/50;
   137→    }
   138→  body {
   139→    @apply bg-background text-foreground;
   140→    }
   141→  html {
   142→    @apply font-sans;
   143→    }
   144→}
   145→
   146→/* ===== JukuBox.ai ランディングページ用スタイル ===== */
   147→
   148→/* フィルムグレイン質感 */
   149→body::after {
   150→  content: '';
   151→  position: fixed;
   152→  inset: 0;
   153→  background-image: url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/><feColorMatrix type='saturate' values='0'/></filter><rect width='200' height='200' filter='url(%23n)' opacity='0.18'/></svg>");
   154→  opacity: 0.055;
   155→  pointer-events: none;
   156→  z-index: 9000;
   157→  mix-blend-mode: overlay;
   158→}
   159→
   160→@keyframes juku-record-spin {
   161→  from { transform: rotate(0deg); }
   162→  to { transform: rotate(360deg); }
   163→}
   164→
   165→@keyframes juku-breathe {
   166→  0%, 100% { opacity: 0.85; }
   167→  50% { opacity: 1; }
   168→}
   169→
   170→@keyframes juku-glow-gold {
   171→  0%, 100% {
   172→    box-shadow: 0 0 8px var(--gold-dim), 0 0 16px oklch(0.75 0.12 77 / 0.2);
   173→  }
   174→  50% {
   175→    box-shadow: 0 0 12px var(--gold), 0 0 28px oklch(0.75 0.12 77 / 0.25);
   176→  }
   177→}
   178→
   179→.juku-glow-gold-text {
   180→  text-shadow: 0 0 18px oklch(0.75 0.12 77 / 0.45);
   181→}
   182→
   183→.juku-glass {
   184→  background: var(--card);
   185→  backdrop-filter: blur(20px);
   186→  -webkit-backdrop-filter: blur(20px);
   187→  border: 1px solid oklch(1 0 0 / 0.18);
   188→}
   189→
   190→.juku-grid-bg {
   191→  background-image:
   192→    linear-gradient(var(--grid-line) 1px, transparent 1px),
   193→    linear-gradient(90deg, var(--grid-line) 1px, transparent 1px);
   194→  background-size: 48px 48px;
   195→}
   196→
   197→.juku-record-spin {
   198→  animation: juku-record-spin 32s linear infinite;
   199→}
   200→
   201→.juku-breathe {
   202→  animation: juku-breathe 4s ease-in-out infinite;
   203→}
   204→
   205→.juku-glow-border {
   206→  animation: juku-glow-gold 4s ease-in-out infinite;
   207→}
   208→
   209→.juku-cta-btn-primary {
   210→  position: relative;
   211→  background: transparent;
   212→  border: 1px solid var(--gold);
   213→  color: var(--gold);
   214→  transition: all 0.35s ease;
   215→  overflow: hidden;
   216→  cursor: pointer;
   217→}
   218→
   219→.juku-cta-btn-primary::before {
   220→  content: '';
   221→  position: absolute;
   222→  inset: 0;
   223→  background: var(--gold);
   224→  transform: scaleX(0);
   225→  transform-origin: left;
   226→  transition: transform 0.35s ease;
   227→  z-index: 0;
   228→}
   229→
   230→.juku-cta-btn-primary:hover::before {
   231→  transform: scaleX(1);
   232→}
   233→
   234→.juku-cta-btn-primary:hover {
   235→  color: var(--background);
   236→  box-shadow: 0 0 16px oklch(0.75 0.12 77 / 0.3);
   237→}
   238→
   239→.juku-cta-btn-primary span {
   240→  position: relative;
   241→  z-index: 1;
   242→}
   243→
   244→.juku-cta-btn-secondary {
   245→  position: relative;
   246→  background: transparent;
   247→  border: 1px solid oklch(1 0 0 / 0.2);
   248→  color: var(--muted-foreground);
   249→  transition: all 0.3s ease;
   250→  cursor: pointer;
   251→}
   252→
   253→.juku-cta-btn-secondary:hover {
   254→  border-color: oklch(1 0 0 / 0.45);
   255→  color: var(--foreground);
   256→}
   257→
   258→.juku-feature-card {
   259→  position: relative;
   260→  overflow: hidden;
   261→  transition: all 0.4s ease;
   262→}
   263→
   264→.juku-feature-card::before {
   265→  content: '';
   266→  position: absolute;
   267→  top: 0;
   268→  left: 0;
   269→  right: 0;
   270→  height: 1px;
   271→  background: linear-gradient(90deg, transparent, var(--gold-dim), transparent);
   272→}
   273→
   274→.juku-feature-card:hover {
   275→  transform: translateY(-3px);
   276→  border-color: oklch(1 0 0 / 0.12);
   277→}
   278→
   279→.juku-divider {
   280→  width: 100%;
   281→  height: 1px;
   282→  background: linear-gradient(90deg, transparent, var(--gold-dim) 30%, var(--gold-dim) 70%, transparent);
   283→  opacity: 0.5;
   284→}

